module RefModule(output reg [7:0] reg_0x45, input wire reset, input wire wenb, input wire [7:0] in_data, input wire clk);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)
    begin
        if(reset==0) begin
            if(wenb==0)
                reg_0x45<=in_data;
            else
                reg_0x45<=reg_0x45;
        end
        else
            reg_0x45<=8'h00;
    end
endmodule
